#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // Output shape: [N, Cout, Ho, Wo] with stride=(1,1), padding=(0,0), dilation=(1,1)
    TORCH_CHECK(x.dim() == 4, \"x must be 4D NCHW\");
    TORCH_CHECK(weight.dim() == 4, \"weight must be 4D OIHW\");
    int64_t N = x.size(0);
    int64_t Cin = x.size(1);
    int64_t H = x.size(2);
    int64_t W = x.size(3);
    int64_t Cout = weight.size(0);
    int64_t Kh = weight.size(2);
    int64_t Kw = weight.size(3);
    int64_t Ho = (H - Kh) + 1;
    int64_t Wo = (W - Kw) + 1;

    at::Tensor y = at::empty({N, Cout, Ho, Wo}, x.options());

    EXEC_NPU_CMD(aclnnConvStandard2dAsymmetricInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_standard_2d_asymmetric_input_asymmetric_kernel_custom", &conv2d_impl_npu);
